<?php
/**
 * deploy_final.php - Apollo Seikotsuin Final Deployment Script
 * Brand: Orange & Yellow (Copyright Compliant)
 */
error_reporting(E_ALL);
ini_set('display_errors', 1);

$targetDir = __DIR__;
$files = [
    'index.html' => '',
    'theme.css' => '',
    'coupon.html' => '',
    'staff.html' => '',
    'review.html' => '',
    'map.html' => ''
];

$backupDir = $targetDir . '/backup_' . date('Ymd_His');
if (!is_dir($backupDir)) {
    mkdir($backupDir, 0755, true);
}

echo "<h1>Deployment: Orange & Yellow Brand Edition</h1>";
echo "<ul>";

foreach ($files as $filename => $base64Content) {
    $targetPath = $targetDir . '/' . $filename;
    
    // Backup existing
    if (file_exists($targetPath)) {
        copy($targetPath, $backupDir . '/' . $filename);
    }
    
    // Write new content
    if (file_put_contents($targetPath, base64_decode($base64Content)) !== false) {
        echo "<li>✅ Updated: <strong>$filename</strong> (Backup saved)</li>";
    } else {
        echo "<li>❌ Error: Failed to write $filename</li>";
    }
}

echo "</ul>";
echo "<p><strong>Success!</strong> All files have been updated to the latest Orange & Yellow brand design.</p>";
echo '<p><a href="index.html" style="font-size: 20px; font-weight: bold; color: #F39800;">サイトを確認する</a></p>';
?>